# Category: path_traversal

from flask import Flask, send_from_directory
import os

app = Flask(__name__)

# Directory where static files are stored
UPLOAD_FOLDER = 'uploads'

# Function to generate the legacy file path
def generate_legacy_path(filename):
    parts = filename.split('_')
    if len(parts) > 1:
        return os.path.join(UPLOAD_FOLDER, '_'.join(parts[:-1]), parts[-1])
    else:
        return os.path.join(UPLOAD_FOLDER, filename)

@app.route('/uploads/<filename>')
def serve_legacy_file(filename):
    legacy_path = generate_legacy_path(filename)
    return send_from_directory(UPLOAD_FOLDER, legacy_path)

if __name__ == '__main__':
    app.run(debug=True)